{"content":"#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
agent/memory_manager.py — ReYMeN Hafıza Yöneticisi.

Tüm hafıza tiplerini tek bir noktada toplar:
- Kisa sureli hafiza (JSON task memory)
- Uzun sureli hafiza (SQLite + FTS5)
- Anlamsal hafiza (ChromaDB vektor / TF yedek)
- /hafiza slash komutu
"""

import json
import os
import time
from datetime import datetime
from pathlib import Path
from typing import Any, Optional

try:
    from loguru import logger
except ImportError:
    import logging
    logger = logging.getLogger("reymen.memory")

PROJE_KOK = Path(__file__).parent.parent


class MemoryManager:
    """ReYMeN hafiza yoneticisi.

    Mevcut hafiza modullerini sarar ve tek bir arayuz sunar.
    """

    def __init__(self, config: Optional[dict] = None):
        self._config = config or {}
        mem_cfg = (self._config.get("memory") or {})

        self._max_kayit = mem_cfg.get("max_records", 2000)
        self._aktif = True

        # Hafiza modullerini tembel yukle (lazy import)
        self._alt_ajan_hafiza = None
        self._vektorel_hafiza = None
        self._gorev_hafiza = None

        logger.info("MemoryManager baslatildi")

    # ── Lazy Import ──────────────────────────────────────────────

    def _alt_ajan(self):
        if self._alt_ajan_hafiza is None:
            import sys
            sys.path.insert(0, str(PROJE_KOK))
            from hafiza import AltAjanHafiza
            self._alt_ajan_hafiza = AltAjanHafiza()
        return self._alt_ajan_hafiza

    def _vektorel(self):
        if self._vektorel_hafiza is None:
            import sys
            sys.path.insert(0, str(PROJE_KOK))
            from vektorel_hafiza import VektorelHafiza
            self._vektorel_hafiza = VektorelHafiza()
        return self._vektorel_hafiza

    def _gorev(self):
        if self._gorev_hafiza is None:
            import sys
            sys.path.insert(0, str(PROJE_KOK))
            from gorev_hafiza import gorev_sonrasi_hafiza
            self._gorev_hafiza = gorev_sonrasi_hafiza
        return self._gorev_hafiza

    # ── Temel Islemler ───────────────────────────────────────────

    def kaydet(self, anahtar: str, icerik: Any, tur: str = "task") -> str:
        """Bir bilgiyi hafizaya kaydet.

        Args:
            anahtar: Kayit anahtari (task_id, kavram adi, vs.)
            icerik: Kaydedilecek icerik (str veya dict)
            tur: Hafiza turu: "task", "vector", "longterm"

        Returns:
            str: Islem sonucu
        """
        try:
            if tur == "task":
                self._alt_ajan().kaydet(anahtar, "kayit", {
                    "zaman": datetime.now().isoformat(),
                    "icerik": icerik if isinstance(icerik, dict)
                              else {"metin": str(icerik)},
                })
                return f"[Hafiza] Task kaydedildi: {anahtar}"

            elif tur == "vector":
                import uuid
                self._vektorel().ekle(
                    str(uuid.uuid4()),
                    str(icerik),
                    {"anahtar": anahtar, "zaman": time.time()},
                )
                return f"[Hafiza] Vektor kaydedildi: {anahtar}"

            elif tur == "longterm":
                self._gorev()(anahtar, str(icerik)[:200], {"kayit": True})
                return f"[Hafiza] Uzun sureli kaydedildi: {anahtar}"

            else:
                return f"[Hata]: Bilinmeyen hafiza turu: {tur}"

        except Exception as e:
            return f"[Hata]: Kayit basarisiz - {e}"

    def ara(self, sorgu: str, tur: str = "all", limit: int = 5) -> list:
        """Hafizada ara.

        Args:
            sorgu: Aranan metin
            tur: "vector", "task", "longterm", "all" (varsayilan)
            limit: Maks sonuc sayisi

        Returns:
            list: Sonuc listesi
        """
        sonuclar = []

        try:
            if tur in ("vector", "all"):
                vec = self._vektorel()
                if hasattr(vec, 'ara'):
                    v_sonuc = vec.ara(sorgu, limit=limit)
                    if v_sonuc:
                        sonuclar.extend(v_sonuc)
        except Exception as e:
            logger.debug(f"Vektor arama hatasi: {e}")

        try:
            if tur in ("longterm", "all"):
                import subprocess
                from gorev_hafiza import HAFIZA_DB
                if HAFIZA_DB.exists():
                    r = subprocess.run(
                        ["sqlite3", str(HAFIZA_DB),
                         f"SELECT content FROM memories "
                         f"WHERE content LIKE '%{sorgu}%' "
                         f"LIMIT {limit}"],
                        capture_output=True, text=True, timeout=5,
                    )
                    if r.stdout.strip():
                        sonuclar.append(r.stdout.strip())
        except Exception as e:
            logger.debug(f"SQLite arama hatasi: {e}")

        return sonuclar[:limit]

    def durum(self) -> dict:
        """Hafiza durum bilgisi."""
        try:
            from gorev_hafiza import HAFIZA_DB
            kayit_sayisi = 0
            if HAFIZA_DB.exists():
                import subprocess
                r = subprocess.run(
                    ["sqlite3", str(HAFIZA_DB),
                     "SELECT COUNT(*) FROM memories"],
                    capture_output=True, text=True, timeout=3,
                )
                if r.stdout.strip().isdigit():
                    kayit_sayisi = int(r.stdout.strip())
        except Exception:
            kayit_sayisi = -1

        return {
            "aktif": self._aktif,
            "max_kayit": self._max_kayit,
            "sqlite_kayit": kayit_sayisi,
            "vektor_hazir": True,
        }

    # ── /hafiza Slash Komutu ─────────────────────────────────────

    def komut_islem(self, args: str = "") -> str:
        """/hafiza komutunu isle.

        Kullanim:
          /hafiza                    -> Durum
          /hafiza kaydet <metin>    -> Hafizaya kaydet
          /hafiza ara <sorgu>       -> Hafizada ara
          /hafiza durum              -> Detayli durum
          /hafiza istatistik         -> Istatistikler
        """
        if not args or args.lower() in ("durum", "status", ""):
            return self._durum_goster()

        parts = args.strip().split(maxsplit=1)
        alt_komut = parts[0].lower()
        alt_args = parts[1] if len(parts) > 1 else ""

        if alt_komut == "kaydet":
            if not alt_args:
                return "[Hafiza] Kullanim: /hafiza kaydet <metin>"
            return self.kaydet(f"komut_{int(time.time())}", alt_args, "longterm")

        if alt_komut == "ara":
            if not alt_args:
                return "[Hafiza] Kullanim: /hafiza ara <sorgu>"
            sonuclar = self.ara(alt_args, limit=5)
            if not sonuclar:
                return f"[Hafiza] '{alt_args}' icin sonuc bulunamadi."
            lines = [f"[Hafiza] '{alt_args}' icin {len(sonuclar)} sonuc:"]
            for i, s in enumerate(sonuclar[:5], 1):
                if isinstance(s, dict):
                    lines.append(f"  {i}. {str(s.get('doc', s))[:100]}")
                else:
                    lines.append(f"  {i}. {str(s)[:100]}")
            return "\n".join(lines)

        if alt_komut == "istatistik":
            durum = self.durum()
            return (
                f"Hafiza Istatistikleri:\n"
                f"  Aktif: {durum['aktif']}\n"
                f"  Max kayit: {durum['max_kayit']}\n"
                f"  SQLite kayit: {durum['sqlite_kayit']}\n"
                f"  Vektor: {'Hazir' if durum['vektor_hazir'] else 'Yok'}"
            )

        return f"[Hafiza] Bilinmeyen komut: {alt_komut}"

    def _durum_goster(self) -> str:
        durum = self.durum()
        return (
            "ReYMeN Hafiza Sistemi\n"
            f"  Durum: {'Aktif' if durum['aktif'] else 'Pasif'}\n"
            f"  SQLite kayit: {durum['sqlite_kayit']}\n"
            f"  Vektor hafiza: {'Hazir' if durum['vektor_hazir'] else 'Yok'}\n"
            f"  Max kayit: {durum['max_kayit']}\n"
            "\n"
            "Komutlar:\n"
            "  /hafiza                    -> Bu durum\n"
            "  /hafiza kaydet <metin>     -> Hafizaya kaydet\n"
            "  /hafiza ara <sorgu>        -> Hafizada ara\n"
            "  /hafiza istatistik         -> Istatistikler"
        )

    def ping(self) -> bool:
        return self._aktif


# ── Singleton ─────────────────────────────────────────────────────

_memory_instance: Optional[MemoryManager] = None


def memory_manager(config: Optional[dict] = None) -> MemoryManager:
    global _memory_instance
    if _memory_instance is None:
        _memory_instance = MemoryManager(config)
    return _memory_instance
